using OrdinaryDiffEqLowStorageRK
using Trixi

###############################################################################
# semidiscretization of the visco-resistive compressible MHD equations

prandtl_number() = 0.72
mu() = 1e-3
eta() = 1e-3

equations = IdealGlmMhdEquations2D(5 / 3)
equations_parabolic = ViscoResistiveMhd2D(equations, mu = mu(),
                                          Prandtl = prandtl_number(),
                                          eta = eta(),
                                          gradient_variables = GradientVariablesPrimitive())

volume_flux = (flux_central, flux_nonconservative_powell)
solver = DGSEM(polydeg = 3,
               surface_flux = (FluxLaxFriedrichs(max_abs_speed_naive),
                               flux_nonconservative_powell),
               volume_integral = VolumeIntegralFluxDifferencing(volume_flux))

coordinates_min = (-1.0, -1.0) # minimum coordinates (min(x), min(y))
coordinates_max = (1.0, 1.0) # maximum coordinates (max(x), max(y))

# Create a uniformly refined mesh with periodic boundaries
mesh = TreeMesh(coordinates_min, coordinates_max,
                initial_refinement_level = 1,
                periodicity = true,
                n_cells_max = 10_000) # set maximum capacity of tree data structure

# This is a modified 2D Alfvén wave with a periodic density variation, following
# Altmann (2012) http://dx.doi.org/10.18419/opus-3895.
# Domain: [-1, 1]^2, γ = 5/3.
function initial_condition_constant_alfven_2d(x, t, equations)
    omega = 2.0 * pi
    # r = length of the computational domain
    r = 2.0
    # e = perturbation amplitude
    e = 0.02
    nx = 1 / sqrt(r^2 + 1.0)
    ny = r / sqrt(r^2 + 1.0)
    sqr = 1.0
    Va = omega / (ny * sqr)
    phi_alv = omega / ny * (nx * (x[1] - 0.5 * r) + ny * (x[2] - 0.5 * r)) - Va * t

    rho = 1.0 + e * cos(phi_alv + 1.0)
    v1 = -e * ny * cos(phi_alv) / rho
    v2 = e * nx * cos(phi_alv) / rho
    v3 = e * sin(phi_alv) / rho
    p = 1.0 + e * cos(phi_alv + 1.0)
    B1 = nx - rho * v1 * sqr
    B2 = ny - rho * v2 * sqr
    B3 = -rho * v3 * sqr
    psi = 0.0

    return prim2cons(SVector(rho, v1, v2, v3, p, B1, B2, B3, psi), equations)
end

